var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"그로니아 수도권 상공\\n페가수스 수송기, <color=#ffd34c>메이즈 전대</color> 초계 임무 중\\nCSE Level <color=#ffd34c>1.3</color>","JPN":"グロニア首都圏上空\\nペガサス輸送機、<color=#ffd34c>メイズ戦隊</color>哨戒任務中\\nCSE Level <color=#ffd34c>1.3</color>","ENG":"Gronia Metropolitan Airspace\\nTransport Plane Pegasus, <color=#ffd34c>Maze Division</color> Patrolling\\nCSE Level <color=#ffd34c>1.3</color>","TWN":"格羅尼亞首都上空\\n天馬運輸機，<color=#ffd34c>梅茲戰隊</color> 執行巡邏任務中\\nCSE Level <color=#ffd34c>1.3</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_UI_RECRUITMNET_HELICOPTER_LAND"},{"id":"L3_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"현재 고도는 4천. 기체 상태는 양호하며 침식파 반응도 예상 범위 이내입니다.","JPN":"ただいま高度は4000。機体の状態は良好、侵食波反応も予想範囲内です。","ENG":"The current altitude is 4000. We’re fine on gas and the Corruption ray response is within the expected range.","TWN":"目前高度4千，機體狀況良好，侵蝕波反應也在預期範圍內。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L4_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"침식 현상의 일종이라지만, 정말 아름다운 하늘이네요. 가능하다면 오래 날고 싶어요.","JPN":"侵食現象の一種ですけど、本当に綺麗な空ですね。できれば長く飛びたいです。","ENG":"They say it’s part of the Counterside Effect, but my, what an absolutely beautiful sky. I hope we fly as long as we can.","TWN":"雖說是侵蝕現象的其中一種，但天空真的好美，可以的話，真希望可以飛久一點～"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래. 남들 앞에서만 적당히 뻣뻣하게 굴어.","JPN":"そう。他の人の前では適度に堅苦しく行動してね。","ENG":"Yes. Just remember to act stiff when you’re around others.","TWN":"嗯嗯，在外人面前要收斂一點。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"지금 우리는 관리국에서 파견한 오피셜 서포트야. 수송기에 탑재된 AI가 감정이 풍부하면 다들 깜짝 놀랄걸.","JPN":"今の私たちは管理局から派遣されたオフィシャルサポート。輸送機に搭載されたAIが感情豊かだったらみんなビックリするわ。","ENG":"We are the Official Support dispatched from the Administration. If everyone sees an AI full of emotion, it would be a little too surprising for them.","TWN":"我們現在的角色可是管理局派來的官方支援，運輸機上搭載的AI如果情感太豐富，其他人會起疑的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"하하, 검문 나온 병사들이 어디서 구한 장비냐고 물어볼 때는 정말 아찔했죠.","JPN":"はは、検問の兵士にどこで手に入れた装備なのかと聞かれた時には本当にヒヤっとしましたね。","ENG":"Ha ha, I drew cold sweat when the soldiers during the inspection asked where we got such hi-tech equipment.","TWN":"哈哈，那些士兵問我這些裝備是哪來的時候，真的嚇我一跳呢！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"난 그쪽 무장 상태가 더 아찔하더라.","JPN":"私はそっちの武装状態の方がもっとヒヤっとしたわよ。","ENG":"I found the state of their equipment to be more surprising honestly.","TWN":"我才被你的武裝狀態給嚇到呢！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"요즘 시대에 누가 그런 구식 무기로 무장시키니? 애들 위험하게.","JPN":"今時あんな旧型の武器で武装させるなんて有り得ないわよね？　子どもたちが危ないでしょ。","ENG":"They still use such old-fashioned weapons in this day and age. So dangerous.","TWN":"最近誰會用這種舊型武器？沒問題吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"저희가 동면해 있는 동안 계속 내전 상태였다니, 어쩔 수 없었겠죠.","JPN":"私たちが冬眠してる間ずっと内戦状態だったそうですから、仕方がなかったんでしょう。","ENG":"They were in a state of constant civil war while we were in cryostasis. I guess it couldn’t be helped.","TWN":"有什麼辦法，誰叫我們冬眠這段期間，一直是在內戰的狀態。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그보다 이제 곧 초계 임무가 끝납니다. 오늘은 조금 푹 쉬십시오, 부전대장님.","JPN":"それよりもうすぐ哨戒任務も終わりです。今日はよくお休みください、副戦隊長。","ENG":"Anyways, the patrol mission will be over soon. Get some rest, Deputy Commander.","TWN":"不過巡邏任務就快結束了，副戰隊長，你今天就好好休息吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"응? 시간이 벌써 그렇게 됐나?","JPN":"うん？　もうそんな時間？","ENG":"Huh? It’s already that time of day?","TWN":"嗯？都已經是這個時間啦？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"난 됐어. 다른 애들이나 신경 써 줘.","JPN":"私は大丈夫。他の子どもたちを気にかけて。","ENG":"I’m fine, thank you. Look after the other ones.","TWN":"我沒關係，你去照顧其他孩子吧～"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"관리자님의 당부 때문에 그러십니까?","JPN":"管理者様からの要請のためですか？","ENG":"Are you doing this because of the Administrator’s request?","TWN":"是因為管理者的吩咐嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"글쎄……. 어떠려나.","JPN":"さあ……どうかしら。","ENG":"Well... What do you think?","TWN":"這個嘛……會怎麼樣呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"초계 임무?","JPN":"哨戒任務？","ENG":"The patrol mission?","TWN":"巡邏任務?"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다네. 그로니아 정부가 최근 치안 문제로 신경이 곤두서 있다더군.","JPN":"そうだ。グロニアの政府が最近治安の問題で神経を使っているらしい。","ENG":"That's right. I heard the Gronia government has been on edge over security issues these days.","TWN":"沒錯， 聽說格羅尼亞政府，最近因為治安問題很傷腦筋。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"샤레이드를 통해 요청이 들어와서, 관리국 명의로 인력을 지원할 예정일세.","JPN":"シャレードを通じて要請があったのでね。管理局の名義で人力をを支援する予定だ。","ENG":"We received a request via Charade, and we will provide support under the name of the Administration.","TWN":"於是透過查雷德來請求支援，因此我打算以管理局的名義派兵支援。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그 나라 사정은 뉴스를 통해 듣긴 했는데…….","JPN":"その国の事情はニュースで聞いてはいたけれど……","ENG":"I had heard about the country’s situation in the news...","TWN":"那個國家的事我是有在新聞上看到……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"요즘 같은 시기에 그래도 되겠어? 류드밀라도 조율인지 뭔지 때문에 부재 중이잖아?","JPN":"こんな時期にそれでもいいの？　リュドミラちゃんも調律かなんかで不在でしょ？","ENG":"Looks like this time period isn’t any different. Lyudmila’s also absent because she’s still in the middle of tuning.","TWN":"但現在合適嗎？盧德米拉不是也因為人力調整還什麼的，所以現在不在嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"전대장은 너무 걱정 말게. 그녀도 최선을 다하고 있어.","JPN":"戦隊長は心配無用だ。彼女も頑張っているんだ。","ENG":"Don’t worry about the Commander, she’s doing her best too.","TWN":"戰隊長那邊你不用擔心，她也在努力執行任務中。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯嗯……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"알겠어. 코핀 컴퍼니에도 믿음직스러운 아이들은 많으니까.","JPN":"わかったわ。コフィンカンパニーにも頼もしい子はいっぱいいるから。","ENG":"Understood. There are also many capable kids in Coffin Company.","TWN":"好吧，科芬公司裡也有許多信得過的孩子。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"예전처럼 후방을 지킨다고 보면 되려나.","JPN":"昔のように後方担当でいいのね？","ENG":"Are we taking care of the rear like we did before?","TWN":"我們就跟以前一樣，負責後方就可以吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇지. 단순한 대기 임무라고는 생각하지 말아 주게.","JPN":"そうだな。単なる待機任務とは思わないでくれ。","ENG":"Yes. But don’t think of it as a simple standby mission.","TWN":"沒錯，不過不要把這視作普通的任務。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……그래? 당신, 그 나라에 또 뭘 숨겨 둔 거야?","JPN":"……そう？　あなた、その国にまた何を隠しておいたの？","ENG":"...Very well. What else are you hiding in the country?","TWN":"……為什麼？你又藏了什麼東西在那個國家裡嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하. 누가 들으면 다람쥐라도 된 줄 알겠군.","JPN":"はは。誰かが聞いたらリスと勘違いされそうだな。","ENG":"Ha ha. If someone were listening, they might think of me as a squirrel.","TWN":"哈哈，不知情的人聽到，還以為我是花栗鼠喜歡藏東西呢～"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네도 구 관리국 시절이 어땠는지는 잘 알겠지. 지금도 상황은 별반 다르지 않다네.","JPN":"君も旧管理局時代がどうだったかはよくわかっているだろう。今も状況はあまり変わらない。","ENG":"You remember what the Old Administration was like. Things haven’t changed all that much.","TWN":"你應該也清楚舊管理局時期的情況，現在情況也沒比那時候好。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"위기는…….","JPN":"危機は……","ENG":"Crises...","TWN":"危機……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……항상 도처에 도사리고 있다.","JPN":"……いつも至る所に潜んでいる。","ENG":"...are all over the place all the time.","TWN":"……四伏。"},"stage":{"bg":"BLACK","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"모네카, 침식파 반응인가?","JPN":"モネカ、侵食波反応か？","ENG":"Moneka, what’s the Corruption ray response?","TWN":"莫奈卡，是侵蝕波反應嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"네. 지상에서 타나베린을 향해 이동하는 침식체 군집이 포착됐어요.","JPN":"はい。地上でタナベリンに向けて移動している侵食体の群れを識別しました。","ENG":"A cluster of Corrupted Objects has been spotted on the ground moving towards Tanaberin.","TWN":"是，在地上發現一群朝著達那貝林移動的侵蝕體。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"규모는 그리 크지 않지만……. 3종 침식체 2체가 포착됩니다.","JPN":"そこまで大規模ではないですけど……2体の第3種侵食体を捉えました。","ENG":"It’s not that large but... It’s sensing two Category 3s.","TWN":"規模不算大……但有2個3類侵蝕體。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"2체? 하나도 아니고?","JPN":"2体？　1体ではなく？","ENG":"Two? Not just one?","TWN":"2個？你確定不是1個？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"그렇습니다. 그로니아 측 기록에는 이전까지 없던 사례예요.","JPN":"そうです。グロニア側の記録には前例のないことです。","ENG":"Affirmative. This instance has not occurred in Gronia before.","TWN":"是2個，根據格羅尼亞的紀錄，這是前所未見的情況。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"흐음……. 이례적이란 말이지. 느낌이 안 좋네.","JPN":"ふん……イレギュラーってことね。いやな予感がするわ。","ENG":"Hmm... That’s strange. I have a bad feeling about this.","TWN":"嗯嗯……例外的意思是吧？我有不好的預感。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"시 외곽 방어 포대, 포격을 시작했습니다.","JPN":"市の外郭防御砲台、砲撃を開始しました。","ENG":"Outer City Defense’s Defense Turret has begun firing.","TWN":"城外防禦砲台，開始發射。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"우으……. 아니나 다를까 위력이 너무 약해요. 제가 들어가면 더 잘 쏠 수 있을 텐데.","JPN":"うぅ……予想どおり威力が弱すぎです。私が入ったらもっとうまく撃てるのに。","ENG":"Argh... It’s too weak. If only I could just take control of the system myself.","TWN":"唔……威力果然太弱，我出馬的話應該會更厲害。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그래도 늦지 않게 포착해서 다행이군요.","JPN":"それでも早めに気付いてよかったですね。","ENG":"Still. I’m glad you sensed it before it was too late.","TWN":"至少我們有即時發現！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"맞아. 그렇지만 에스타크를 발굴해서 고정 포대로 쓰는 건 조금 의외였어.","JPN":"まったくね。だけどエスタークを発掘して固定砲台に使うのはちょっと意外だったわ。","ENG":"Right. But excavating the Estaques and using it as a turret was a little unexpected.","TWN":"是沒錯，但我有點意外，竟然將艾斯塔克當作固定砲台使用。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"조금만 손봐 주면 더 쓸 만해질 텐데……. 어떻게 안 되려나.","JPN":"少し手入れをすればもっと使えるようになると思うけど……どうにかならないのかしら。","ENG":"It’d be better if we could fix it up a bit... Is there really no other way...?","TWN":"只要稍微修理一下，效能應該會更好……有什麼辦法嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"참아 주시죠. 한 번 손을 대기 시작하면 끝도 없을 겁니다.","JPN":"我慢してください。一度手を出したらキリがありません。","ENG":"Please just bear with it. Once you start tinkering with it, there will be no end to it.","TWN":"請忍耐一下，一旦出手就會很難收手。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"……음? 모네카, 침식체 군집이 더 있나?","JPN":"……おや？　モネカ、侵食体の群れがまだあるのか？","ENG":"...Huh? Moneka, is that another Corrupted Object cluster?","TWN":"……嗯？莫奈卡，還有其他侵蝕體嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"아, 아뇨! 구 관리국 데이터베이스에 있던 반응이 관측됐어요!","JPN":"い、いいえ！　旧管理局のデータベースにあった反応が観測されました！","ENG":"Ah, that can’t be! I’m getting a return from the Old Administration database!","TWN":"不…不是！監測到是舊管理局資料庫的反應！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"침식파의 밀도는 기록보다 낮지만……. 이 시그니처 타입은…….","JPN":"侵食波の密度は記録より低いですけど……このシグネチャータイプは……","ENG":"The density of the Corruption rays is lower than what’s recorded, but... This signature type is…","TWN":"侵蝕波的密度雖然比紀錄低……但這個標誌類型是……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"엘리시움! 최고 단원으로 추정됩니다!","JPN":"エリシウム！　首席奏者と推測されます！","ENG":"Elysium! Assumed to be one of the Elite Members!","TWN":"愛樂！推測是首席樂手！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"최고 단원이라고?","JPN":"首席奏者？","ENG":"Did you say one of the Elite Members?","TWN":"首席樂手？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"설마……. 여기로 온 건가?","JPN":"まさか……ここに来たのか？","ENG":"No way... Coming this way?","TWN":"該不會……跑到這裡來？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래, 어쩐지. 항상 이런 식이라니까.","JPN":"そう、やっぱり。いつもこうなるんだから。","ENG":"Ah yes, of course. Things always turn out like this.","TWN":"難怪，每次都差不多的套路。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"모네카. 반응이 관측된 곳으로 기수를 돌려.","JPN":"モネカ。反応が観測された方向に旋回しなさい。","ENG":"Moneka. Turn us around to where the signal was detected.","TWN":"莫奈卡，將機頭轉向監測到反應的地方！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님, 전대장님도 부재 중이신데 괜찮겠습니까?","JPN":"副戦隊長、戦隊長も不在ですが大丈夫ですか？","ENG":"Deputy Commander, the Commander is absent now. Will everything be fine?","TWN":"副戰隊長，現在戰隊長又不在，這樣沒關係嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"심경은 이해합니다만, 지나치게 감정적으로 움직이시는 건 아닐지…….","JPN":"お気持ちはわかりますが、感情に任せすぎているのでは……","ENG":"I understand how you feel, but I'm concerned you’re being too emotional.","TWN":"我明白你的心情，但這時候這麼做是否有點衝動……"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"구 관리국 시절에도 감시망을 피해 온 녀석들이야. 굳이 우리에게 위치를 노출한 것부터 이상하지 않니?","JPN":"旧管理局時代にも監視網を潜り抜けてきた奴らなのよ。あえて私たちに位置を教えるのはおかしくない？","ENG":"Those bastards have been avoiding us ever since the Old Administration. Isn’t it strange that they’ve revealed themselves now?","TWN":"他們可是能夠躲過舊管理局監視網的傢伙，竟然會被我們監測到位置，你難道不覺得奇怪嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"이건 초대장이야. 그 가식쟁이 개자식들의.","JPN":"これは招待状よ。あの見栄っ張りのクソ野郎どもからのね。","ENG":"They’re inviting us to come. Those demons.","TWN":"這是那些傢伙發來的邀請卡。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"초대장을 받았으면 얼굴은 비춰 주는 게 인지상정이지.","JPN":"招待状をもらったからには顔を出すのが礼儀ってもんよ。","ENG":"If they invited us, it’s polite for us to show our faces.","TWN":"既然收到邀請卡，那露個臉是基本的禮貌吧～"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};